"use client";

import { NavigationList as NavigationListRoot, type NavigationListProps } from "./navigation-list";
import { NavigationListItem, type NavigationListItemProps } from "./navigation-list-item";
import { NavigationListTitle, type NavigationListTitleProps } from "./navigation-list-title";
import { NavigationListStatus, type NavigationListStatusProps } from "./navigation-list-status";
import { NavigationListBadge } from "./navigation-list-badge";
import { NavigationListSubtitle, type NavigationListSubtitleProps } from "./navigation-list-subtitle";
import { NavigationListMeta, type NavigationListMetaProps } from "./navigation-list-meta";

const NavigationList = Object.assign(NavigationListRoot, {
  Item: NavigationListItem,
  Badge: NavigationListBadge,
  Title: NavigationListTitle,
  Status: NavigationListStatus,
  Meta: NavigationListMeta,
  Subtitle: NavigationListSubtitle,
});

export { NavigationList, type NavigationListProps };
export { NavigationListItem, type NavigationListItemProps };
export { NavigationListBadge };
export type { BadgeProps as NavigationListBadgeProps } from "../badge/badge";
export { NavigationListTitle, type NavigationListTitleProps };
export { NavigationListStatus, type NavigationListStatusProps };
export { NavigationListMeta, type NavigationListMetaProps };
export { NavigationListSubtitle, type NavigationListSubtitleProps };

"use client";

import { type ComponentPropsWithRef, type ReactNode, type KeyboardEvent, useId, useMemo, useRef } from "react";
import { collectListboxItems, getEncodedListboxItemId, useListbox } from "@/hooks/use-listbox";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { NavigationListContext } from "./navigation-list-context";
import { NavigationListItem } from "./navigation-list-item";

export interface NavigationListProps
  extends Omit<ComponentPropsWithRef<"div">, "children" | "onKeyDown" | "onSelect"> {
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  highlighted?: string | null;
  defaultHighlighted?: string | null;
  onSelect?: (id: string) => void;
  onEnter?: (id: string, event: globalThis.KeyboardEvent) => void;
  onHighlightChange?: (id: string | null) => void;
  onNavigationBoundaryReached?: (
    direction: "previous" | "next",
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  focused?: boolean;
  wrap?: boolean;
  autoFocus?: boolean;
  children: ReactNode;
  onKeyDown?: (event: KeyboardEvent) => void;
}

export function NavigationList({
  selectedId: controlledSelectedId,
  defaultSelectedId = null,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onEnter,
  onHighlightChange,
  onNavigationBoundaryReached,
  focused = true,
  wrap = true,
  autoFocus = false,
  className,
  children,
  onKeyDown,
  "aria-label": ariaLabel,
  ref,
  ...rootProps
}: NavigationListProps) {
  const idPrefix = useId();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const items = useMemo(() => collectListboxItems(children, NavigationListItem), [children]);

  const {
    selectedId,
    highlighted,
    handleItemActivate,
    handleItemHighlight,
    getContainerProps,
  } = useListbox({
    selectedId: controlledSelectedId,
    defaultSelectedId,
    highlighted: controlledHighlighted,
    defaultHighlighted,
    onSelect,
    onEnter,
    onHighlightChange,
    onNavigationBoundaryReached,
    wrap,
    idPrefix,
    autoFocus,
    onKeyDown,
    typeahead: true,
    items,
    getItemId: getEncodedListboxItemId,
  });

  const contextValue = useMemo(
    () => ({
      selectedId,
      highlighted,
      activate: handleItemActivate,
      highlight: handleItemHighlight,
      focusContainer: () => containerRef.current?.focus(),
      focused,
      idPrefix,
    }),
    [selectedId, highlighted, handleItemActivate, handleItemHighlight, focused, idPrefix],
  );

  return (
    <NavigationListContext value={contextValue}>
      <div
        {...rootProps}
        {...getContainerProps(composeRefs(containerRef, ref))}
        aria-label={ariaLabel}
        aria-orientation="vertical"
        className={cn("w-full outline-none", className)}
      >
        {children}
      </div>
    </NavigationListContext>
  );
}

"use client";

import {
  Children,
  isValidElement,
  type ComponentPropsWithRef,
  type FocusEvent,
  type MouseEvent,
  type ReactNode,
  useMemo,
} from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useNavigationListContext } from "./navigation-list-context";
import { NavigationListItemContext } from "./navigation-list-item-context";
import { NavigationListMeta } from "./navigation-list-meta";
import { NavigationListSubtitle } from "./navigation-list-subtitle";

const itemVariants = cva("flex cursor-pointer group", {
  variants: {
    active: {
      true: "bg-primary text-primary-foreground",
      false: "hover:bg-secondary border-b border-border/50",
    },
    disabled: {
      true: "opacity-50 cursor-not-allowed",
    },
  },
  defaultVariants: {
    active: false,
    disabled: false,
  },
});

const contentVariants = cva("flex-1 grid grid-cols-[1fr_auto] auto-rows-auto gap-y-0.5", {
  variants: {
    density: {
      compact: "p-2",
      default: "p-3",
      comfortable: "p-4",
    },
  },
  defaultVariants: {
    density: "default",
  },
});

type Density = NonNullable<VariantProps<typeof contentVariants>["density"]>;

function hasDescriptionChild(children: ReactNode, childType: typeof NavigationListMeta | typeof NavigationListSubtitle): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === childType) return true;
    return hasDescriptionChild(child.props.children, childType);
  });
}

export interface NavigationListItemProps
  extends Omit<
    ComponentPropsWithRef<"div">,
    "id" | "children" | "role" | "aria-selected" | "aria-disabled" | "aria-labelledby" | "aria-describedby"
  > {
  id: string;
  density?: Density;
  disabled?: boolean;
  children: ReactNode;
}

export function NavigationListItem({
  id,
  disabled = false,
  density = "default",
  children,
  className,
  ref,
  onClick,
  onMouseDown,
  onFocus,
  ...rootProps
}: NavigationListItemProps) {
  const { selectedId, highlighted, activate, highlight, focusContainer, focused, idPrefix } =
    useNavigationListContext();
  const isSelected = !disabled && selectedId === id;
  const isHighlighted = !disabled && highlighted === id;
  const hasHighlight = highlighted !== null;
  const isActive = !disabled && focused && (hasHighlight ? isHighlighted : isSelected);
  const itemId = getEncodedListboxItemId(idPrefix, id);
  const labelId = `${itemId}-label`;
  const descId = `${itemId}-desc`;
  const describedBy = [
    hasDescriptionChild(children, NavigationListMeta) ? `${descId}-meta` : null,
    hasDescriptionChild(children, NavigationListSubtitle) ? `${descId}-sub` : null,
  ].filter(Boolean).join(" ") || undefined;

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (event.defaultPrevented || disabled) return;
    activate(id);
    focusContainer();
  };

  const handleMouseDown = (event: MouseEvent<HTMLDivElement>) => {
    onMouseDown?.(event);
    if (event.defaultPrevented) return;
    if (disabled) event.preventDefault();
  };

  const handleFocus = (event: FocusEvent<HTMLDivElement>) => {
    onFocus?.(event);
    if (!event.defaultPrevented && !disabled) highlight(id);
  };

  const itemContextValue = useMemo(
    () => ({ labelId, descId }),
    [labelId, descId],
  );

  return (
    <NavigationListItemContext value={itemContextValue}>
      <div
        {...rootProps}
        ref={ref}
        id={itemId}
        role="option"
        aria-labelledby={labelId}
        aria-describedby={describedBy}
        data-value={id}
        data-active={isActive || undefined}
        data-state={isSelected ? "selected" : "unselected"}
        aria-selected={isSelected}
        aria-disabled={disabled || undefined}
        onMouseDown={handleMouseDown}
        onClick={handleClick}
        onFocus={handleFocus}
        className={cn(itemVariants({ active: isActive, disabled }), "focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground", className)}
      >
        <div
          className={cn(
            "w-1 shrink-0",
            isActive ? "bg-primary-foreground/40" : "bg-transparent group-hover:bg-muted"
          )}
        />
        <div className={contentVariants({ density })}>
          {children}
        </div>
      </div>
    </NavigationListItemContext>
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useNavigationListItemContext } from "./navigation-list-item-context";

const SELECTION_INDICATOR = "\u258C";

export interface NavigationListTitleProps {
  children: ReactNode;
  className?: string;
}

export function NavigationListTitle({ children, className }: NavigationListTitleProps) {
  const { labelId } = useNavigationListItemContext();

  return (
    <span id={labelId} className={cn("col-start-1 row-start-1 font-bold flex items-center group-data-[active]:text-primary-foreground", className)}>
      <span aria-hidden="true" className="mr-2 opacity-30 group-data-[active]:opacity-100">{SELECTION_INDICATOR}</span>
      {children}
    </span>
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";

export interface NavigationListStatusProps {
  children: ReactNode;
  className?: string;
}

export function NavigationListStatus({ children, className }: NavigationListStatusProps) {
  return (
    <span className={cn("col-start-2 row-start-1 self-center text-[10px] font-bold text-warning group-data-[active]:text-primary-foreground", className)}>
      {children}
    </span>
  );
}

"use client";

import { createContext, useContext } from "react";

export interface NavigationListContextValue {
  selectedId: string | null;
  highlighted: string | null;
  activate: (id: string) => void;
  highlight: (id: string) => void;
  focusContainer: () => void;
  focused: boolean;
  idPrefix: string;
}

export const NavigationListContext = createContext<NavigationListContextValue | undefined>(undefined);

export function useNavigationListContext() {
  const context = useContext(NavigationListContext);
  if (context === undefined) {
    throw new Error("NavigationListItem must be used within NavigationList");
  }
  return context;
}

"use client";

import { Badge, type BadgeProps } from "../badge/badge";
import { cn } from "@/lib/utils";

export function NavigationListBadge({
  children,
  variant = "neutral",
  size = "sm",
  className,
  ...props
}: BadgeProps) {
  return (
    <Badge
      variant={variant}
      size={size}
      className={cn(
        "group-data-[active]:bg-primary-foreground/15 group-data-[active]:text-primary-foreground group-data-[active]:border-primary-foreground/40",
        className
      )}
      {...props}
    >
      {children}
    </Badge>
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useNavigationListItemContext } from "./navigation-list-item-context";

export interface NavigationListSubtitleProps {
  children: ReactNode;
  className?: string;
}

export function NavigationListSubtitle({ children, className }: NavigationListSubtitleProps) {
  const { descId } = useNavigationListItemContext();

  return (
    <span
      id={`${descId}-sub`}
      className={cn(
        "text-[10px] inline-flex items-center leading-none text-muted-foreground group-data-[active]:text-primary-foreground/70",
        className
      )}
    >
      {children}
    </span>
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useNavigationListItemContext } from "./navigation-list-item-context";

export interface NavigationListMetaProps {
  children: ReactNode;
  className?: string;
}

export function NavigationListMeta({ children, className }: NavigationListMetaProps) {
  const { descId } = useNavigationListItemContext();

  return (
    <div id={`${descId}-meta`} className={cn(
      "col-span-full row-start-2 flex gap-2 items-center group-data-[active]:text-primary-foreground/70",
      className
    )}>
      {children}
    </div>
